'use server';
/**
 * @fileOverview A video generation AI agent using Google's Veo model.
 *
 * - generateKissVideo - A function that handles the video generation process from a combined image.
 * - GenerateKissVideoInput - The input type for the generateKissVideo function.
 * - GenerateKissVideoOutput - The return type for the generateKissVideo function.
 */

import { ai } from '@/ai/genkit';
import { z } from 'genkit';
import { googleAI } from '@genkit-ai/googleai';
import * as fs from 'fs';
import { Readable } from 'stream';

export const GenerateKissVideoInputSchema = z.object({
  combinedImageUri: z.string().describe(
    "A combined photo of two people, as a data URI that must include a MIME type and use Base64 encoding. Expected format: 'data:<mimetype>;base64,<encoded_data>'."
  ),
});
export type GenerateKissVideoInput = z.infer<typeof GenerateKissVideoInputSchema>;

export const GenerateKissVideoOutputSchema = z.object({
  videoDataUri: z.string().optional(),
  error: z.string().optional(),
});
export type GenerateKissVideoOutput = z.infer<typeof GenerateKissVideoOutputSchema>;

export async function generateKissVideo(input: GenerateKissVideoInput): Promise<GenerateKissVideoOutput> {
  return generateKissVideoFlow(input);
}

const generateKissVideoFlow = ai.defineFlow(
  {
    name: 'generateKissVideoFlow',
    inputSchema: GenerateKissVideoInputSchema,
    outputSchema: GenerateKissVideoOutputSchema,
  },
  async (input) => {
    try {
      console.log('[VEO_FLOW] Starting video generation with Veo...');
      let { operation } = await ai.generate({
        model: googleAI.model('veo-2.0-generate-001'),
        prompt: [
          {
            text: 'make the two people in the image kiss passionately, 4k, cinematic, high quality',
          },
          {
            media: {
              contentType: 'image/jpeg',
              url: input.combinedImageUri,
            },
          },
        ],
        config: {
            durationSeconds: 5,
            aspectRatio: '16:9',
        },
      });

      if (!operation) {
        throw new Error('Expected the model to return an operation.');
      }
      
      console.log('[VEO_FLOW] Operation started. Polling for completion...');
      
      let pollCount = 0;
      const maxPolls = 60; // 5 minutes timeout

      while (!operation.done && pollCount < maxPolls) {
        pollCount++;
        console.log(`[VEO_FLOW] Checking operation status (Attempt ${pollCount})...`);
        operation = await ai.checkOperation(operation);
        if (!operation.done) {
            await new Promise((resolve) => setTimeout(resolve, 5000)); // Wait 5 seconds
        }
      }

      if (!operation.done) {
        throw new Error('Video generation timed out after 5 minutes.');
      }

      if (operation.error) {
        console.error('[VEO_FLOW_ERROR] Operation failed:', operation.error);
        throw new Error(`Video generation failed: ${operation.error.message}`);
      }

      const videoPart = operation.output?.message?.content.find((p) => !!p.media && p.media.contentType === 'video/mp4');
      if (!videoPart || !videoPart.media?.url) {
        throw new Error('Failed to find the generated video in the operation output.');
      }
      console.log('[VEO_FLOW] Video generation successful. Fetching video content...');

      // The URL from Veo is temporary and requires the API key to download.
      // We fetch it here on the server and convert it to a data URI to send to the client.
      const fetch = (await import('node-fetch')).default;
      const videoUrl = `${videoPart.media.url}&key=${process.env.GEMINI_API_KEY}`;
      const videoResponse = await fetch(videoUrl);
      
      if (!videoResponse.ok) {
          throw new Error(`Failed to download the generated video. Status: ${videoResponse.status}`);
      }

      const videoBuffer = await videoResponse.buffer();
      const videoDataUri = `data:video/mp4;base64,${videoBuffer.toString('base64')}`;

      console.log('[VEO_FLOW] Successfully converted video to data URI.');
      return { videoDataUri };

    } catch (error) {
      const message = error instanceof Error ? error.message : 'An unknown error occurred during video generation.';
      console.error('[VEO_FLOW_FATAL] A fatal error occurred:', message);
      return { error: message };
    }
  }
);
